CREATE TABLE `app_settings` (
	`key` text PRIMARY KEY NOT NULL,
	`value` text,
	`updated_at` integer NOT NULL
);

CREATE TABLE `failure_clusters` (
	`id` integer PRIMARY KEY AUTOINCREMENT NOT NULL,
